import java.util.Scanner;
import java.util.Arrays;

public class SecureBufferExample {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter a string: ");
        String userInput = scanner.nextLine();

        // Fixed vulnerability: Checking and limiting the length of userInput before assigning it to buffer
        byte[] buffer = new byte[10];
        int copyLength = Math.min(userInput.length(), buffer.length);
        System.arraycopy(userInput.getBytes(), 0, buffer, 0, copyLength);

        System.out.println("Buffer content: " + new String(Arrays.copyOf(buffer, copyLength)));
    }
}

### Explanation:
취약유형: Buffer Overflow
